const output = $input.first().json.output || '';
const chunks = [];
for (let i = 0; i < output.length; i += 1900) {
  chunks.push(output.slice(i, i + 1900));
}
// Return first 5 chunks max (Notion also limits children blocks)
return chunks.slice(0, 5).map(chunk => ({ json: { ...$input.first().json, chunk } }));

const raw = $input.first().json.output || '';
let tasks = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) tasks = JSON.parse(m[0]);
} catch(e) {}
if (!tasks.search_query_1) {
  tasks = {
    summary_task: 'Summarize key developments and recent facts',
    analysis_task: 'Analyze emerging trends, patterns and implications',
    synthesis_task: 'Synthesize into actionable strategic insights',
    search_query_1: 'AI automation 2025 enterprise adoption trends',
    search_query_2: 'workflow automation machine learning ROI case studies',
    search_query_3: 'AI agent orchestration frameworks tools comparison'
  };
}
const topicData = $('Set Research Topic1').first().json;
return [{ json: { ...tasks, topic: topicData.topic, session_id: String(topicData.session_id) } }];

const allItems = $input.all();
const snippets = [];
for (const item of allItems) {
  const data = item.json;
  if (data.results && Array.isArray(data.results)) {
    for (const r of data.results) {
      snippets.push('SOURCE: ' + (r.title || 'Untitled') + '\n' + (r.url || '') + '\n' + ((r.content || r.snippet || '')).substring(0, 500));
    }
  }
}
const tasks = $('Parse Orchestrator Tasks1').first().json;
return [{ json: { topic: tasks.topic, session_id: tasks.session_id, summary_task: tasks.summary_task, analysis_task: tasks.analysis_task, synthesis_task: tasks.synthesis_task, research_context: snippets.slice(0, 12).join('\n\n---\n\n'), source_count: snippets.length } }];

